@kbench.task(
    name="deceptive_stack_machine_obs_learning",
    description=(
        "Observe stack machine traces (PUSH/DUPE/SWAP/ADD/MULMOD/DIVMOD) where early programs "
        "never trigger modular reduction. Infer the hidden prime modulus from later traces and "
        "submit the final stack state for 4 new programs that each require mod reduction."
    ),
)
def deceptive_stack_machine_obs_learning(llm) -> float:
    """Infer a hidden prime modulus from 14 stack machine traces; execute 4 test programs. Float score."""
    prompt, grade_fn = _prepare()
    try:
        response = llm.prompt(prompt, schema=_Answer)
    except Exception:
        response = None
    score, test_results = (
        grade_fn(response)
        if response is not None
        else (
            0.0,
            [
                {
                    "q": i,
                    "expected": _TEST_CASES[i - 1][1],
                    "got": None,
                    "correct": False,
                }
                for i in range(1, 5)
            ],
        )
    )
    reasoning = (
        getattr(response, "reasoning", "") or getattr(response, "thinking", "") or ""
    )
    _log_trace(
        task="deceptive_stack_machine_obs_learning",
        description=_TASK_DESCRIPTION,
        prompt=prompt,
        test_results=test_results,
        score=score,
        reasoning=str(reasoning),
    )
    return score
